/// Parse VexTab from a string. Returns Ok or Error.
let parse (input: string) : Result<VextabNode, string> =
    match run (vextabParser .>> eof) input with
    | Success (v, _, _) -> Result.Ok v
    | Failure (msg, _, _) -> Result.Error msg
